#define SIN_MASK        0x0C00u
#define U0_90           0x0800u
#define U90_180         0x0C00u
#define U180_270        0x0000u
#define U270_360        0x0400u

const float hSin_Cos_Table[1024] = SIN_COS_TABLE;

//    int32_t shindex;
//    uint16_t uhindex;

Trig_Components MCM_Trig_Functions(int16_t hAngle)
{
    int32_t shindex;
    uint16_t uhindex;
		uint16_t indexCHECK;
    Trig_Components Local_Components;

    /* 10 bit index computation  */
    shindex =((int32_t)32768 + (int32_t)hAngle);
    uhindex = (uint16_t)shindex;
    uhindex /= (uint16_t)16;
		indexCHECK = uhindex%1024;
    switch ((uint16_t)(uhindex) & SIN_MASK)
    {
    case U0_90:
        Local_Components.hSin = hSin_Cos_Table[(indexCHECK)];
        Local_Components.hCos = hSin_Cos_Table[(0x03FF-(indexCHECK))];
        break;

    case U90_180:
        Local_Components.hSin = hSin_Cos_Table[(0x03FF-(indexCHECK))];
        Local_Components.hCos = -hSin_Cos_Table[(indexCHECK)];
        break;

    case U180_270:
        Local_Components.hSin = -hSin_Cos_Table[(indexCHECK)];
        Local_Components.hCos = -hSin_Cos_Table[(0x03FF-(indexCHECK))];
        break;

    case U270_360:
        Local_Components.hSin =  -hSin_Cos_Table[(0x03FF-(indexCHECK))];
        Local_Components.hCos =  hSin_Cos_Table[(indexCHECK)];
        break;
    default:
        break;
    }
    return (Local_Components);
}


