uint32_t sqrt32(uint32_t x)
{
	uint32_t m = 0x80000000u, y = 0u, t;
	do if((t = y + (m >> 1)) <= x)
	{
		x -= t;
		y = (y | m) >> 1;
	}
	else y >>= 1; while(m >>= 2);
	return y;
}
